#[derive(Clone, Debug, PartialEq)]
pub enum PipelineStage {
    Simple {
        words: BoundedVec<OsString, 0, LIMIT_STAGE_ITEMS>,
        redirects: u32,
    },
    Compound {
        redirects: u32,
        text: BoundedText<LIMIT_TEXT_BYTES>,
    },
    Function {
        text: BoundedText<LIMIT_TEXT_BYTES>,
    },
    ExtendedTest {
        text: BoundedText<LIMIT_TEXT_BYTES>,
    },
}

impl PipelineStage {
    pub const fn code(&self) -> u64 {
        match self {
            Self::Simple { .. } => 1,
            Self::Compound { .. } => 2,
            Self::Function { .. } => 3,
            Self::ExtendedTest { .. } => 4,
        }
    }
}

impl WireValue for PipelineStage {
    fn encode_atom(&self, output: &mut Vec<u8>) -> Result<(), DecodeError> {
        let mut fields = Vec::new();
        put_u64(&mut fields, self.code());
        match self {
            Self::Simple { words, redirects } => {
                words.encode_atom(&mut fields)?;
                redirects.encode_atom(&mut fields)?;
            }
            Self::Compound { redirects, text } => {
                redirects.encode_atom(&mut fields)?;
                text.encode_atom(&mut fields)?;
            }
            Self::Function { text } => {
                text.encode_atom(&mut fields)?;
            }
            Self::ExtendedTest { text } => {
                text.encode_atom(&mut fields)?;
            }
        }
        put_compound_payload(output, &fields)
    }

    fn decode_atom(input: &mut &[u8]) -> Result<Self, DecodeError> {
        let mut fields = get_atom(input, LIMIT_FRAME_BYTES)?;
        let value = match get_u64(&mut fields)? {
            1 => Self::Simple {
                words: <BoundedVec<OsString, 0, LIMIT_STAGE_ITEMS> as WireValue>::decode_atom(
                    &mut fields,
                )?,
                redirects: <u32 as WireValue>::decode_atom(&mut fields)?,
            },
            2 => Self::Compound {
                redirects: <u32 as WireValue>::decode_atom(&mut fields)?,
                text: <BoundedText<LIMIT_TEXT_BYTES> as WireValue>::decode_atom(&mut fields)?,
            },
            3 => Self::Function {
                text: <BoundedText<LIMIT_TEXT_BYTES> as WireValue>::decode_atom(&mut fields)?,
            },
            4 => Self::ExtendedTest {
                text: <BoundedText<LIMIT_TEXT_BYTES> as WireValue>::decode_atom(&mut fields)?,
            },
            _ => return Err(DecodeError::InvalidValue),
        };
        require_empty(fields)?;
        Ok(value)
    }
}

impl RelationWireValue for PipelineStage {
    fn from_relation(value: &RelationValue) -> Result<Self, String> {
        let (case, fields): (&str, &[RelationValue]) = match value {
            RelationValue::Atom(case) => (case, &[]),
            RelationValue::Compound(case, fields) => (case, fields),
            _ => return Err("expected PipelineStage relation choice".into()),
        };
        match case {
            "simple" => {
                require_relation_arity(fields, 2)?;
                let mut fields = fields.iter();
                Ok(Self::Simple {
                    words: <BoundedVec<OsString, 0, LIMIT_STAGE_ITEMS> as RelationWireValue>::from_relation(fields.next().unwrap())?,
                    redirects: <u32 as RelationWireValue>::from_relation(fields.next().unwrap())?,
                })
            }
            "compound" => {
                require_relation_arity(fields, 2)?;
                let mut fields = fields.iter();
                Ok(Self::Compound {
                    redirects: <u32 as RelationWireValue>::from_relation(fields.next().unwrap())?,
                    text: <BoundedText<LIMIT_TEXT_BYTES> as RelationWireValue>::from_relation(
                        fields.next().unwrap(),
                    )?,
                })
            }
            "function" => {
                require_relation_arity(fields, 1)?;
                let mut fields = fields.iter();
                Ok(Self::Function {
                    text: <BoundedText<LIMIT_TEXT_BYTES> as RelationWireValue>::from_relation(
                        fields.next().unwrap(),
                    )?,
                })
            }
            "extended_test" => {
                require_relation_arity(fields, 1)?;
                let mut fields = fields.iter();
                Ok(Self::ExtendedTest {
                    text: <BoundedText<LIMIT_TEXT_BYTES> as RelationWireValue>::from_relation(
                        fields.next().unwrap(),
                    )?,
                })
            }
            _ => Err(format!("unknown PipelineStage relation choice {case}")),
        }
    }
}

