pub enum ChangeKind {
    Changed,
    Deleted,
    Symlink,
    Created,
    Modified,
    Xattr,
    Directory,
    XattrOnly,
}

impl WireValue for ChangeKind {
    fn encode_atom(&self, output: &mut Vec<u8>) -> Result<(), DecodeError> {
        let code = match self {
            Self::Changed => 1,
            Self::Deleted => 2,
            Self::Symlink => 3,
            Self::Created => 4,
            Self::Modified => 5,
            Self::Xattr => 6,
            Self::Directory => 7,
            Self::XattrOnly => 8,
        };
        put_u64(output, code);
        Ok(())
    }

    fn decode_atom(input: &mut &[u8]) -> Result<Self, DecodeError> {
        match get_u64(input)? {
            1 => Ok(Self::Changed),
            2 => Ok(Self::Deleted),
            3 => Ok(Self::Symlink),
            4 => Ok(Self::Created),
            5 => Ok(Self::Modified),
            6 => Ok(Self::Xattr),
            7 => Ok(Self::Directory),
            8 => Ok(Self::XattrOnly),
            _ => Err(DecodeError::InvalidValue),
        }
    }
}

impl RelationWireValue for ChangeKind {
    fn from_relation(value: &RelationValue) -> Result<Self, String> {
        match relation_atom(value)? {
            "changed" => Ok(Self::Changed),
            "deleted" => Ok(Self::Deleted),
            "symlink" => Ok(Self::Symlink),
            "created" => Ok(Self::Created),
            "modified" => Ok(Self::Modified),
            "xattr" => Ok(Self::Xattr),
            "directory" => Ok(Self::Directory),
            "xattr_only" => Ok(Self::XattrOnly),
            case => Err(format!("unknown ChangeKind relation case {case}")),
        }
    }
}

