#[derive(Clone, Debug, PartialEq)]
pub enum FileDiff {
    Text {
        hunks: BoundedVec<DiffHunk, 0, LIMIT_COLLECTION_ITEMS>,
    },
    Deleted,
    Symlink {
        kind: ChangeKind,
        target: BoundedBytes<LIMIT_PATH_BYTES>,
    },
    Binary {
        kind: ChangeKind,
        content: BoundedBytes<LIMIT_BLOB_BYTES>,
        content_before: Option<BoundedBytes<LIMIT_BLOB_BYTES>>,
    },
    Unavailable {
        message: BoundedText<LIMIT_TEXT_BYTES>,
    },
}

impl FileDiff {
    pub const fn code(&self) -> u64 {
        match self {
            Self::Text { .. } => 1,
            Self::Deleted => 2,
            Self::Symlink { .. } => 3,
            Self::Binary { .. } => 4,
            Self::Unavailable { .. } => 5,
        }
    }
}

impl WireValue for FileDiff {
    fn encode_atom(&self, output: &mut Vec<u8>) -> Result<(), DecodeError> {
        let mut fields = Vec::new();
        put_u64(&mut fields, self.code());
        match self {
            Self::Text { hunks } => {
                hunks.encode_atom(&mut fields)?;
            }
            Self::Deleted => {}
            Self::Symlink { kind, target } => {
                kind.encode_atom(&mut fields)?;
                target.encode_atom(&mut fields)?;
            }
            Self::Binary {
                kind,
                content,
                content_before,
            } => {
                kind.encode_atom(&mut fields)?;
                content.encode_atom(&mut fields)?;
                content_before.encode_atom(&mut fields)?;
            }
            Self::Unavailable { message } => {
                message.encode_atom(&mut fields)?;
            }
        }
        put_compound_payload(output, &fields)
    }

    fn decode_atom(input: &mut &[u8]) -> Result<Self, DecodeError> {
        let mut fields = get_atom(input, LIMIT_FRAME_BYTES)?;
        let value = match get_u64(&mut fields)? {
            1 => Self::Text {
                hunks: <BoundedVec<DiffHunk, 0, LIMIT_COLLECTION_ITEMS> as WireValue>::decode_atom(
                    &mut fields,
                )?,
            },
            2 => Self::Deleted,
            3 => Self::Symlink {
                kind: <ChangeKind as WireValue>::decode_atom(&mut fields)?,
                target: <BoundedBytes<LIMIT_PATH_BYTES> as WireValue>::decode_atom(&mut fields)?,
            },
            4 => Self::Binary {
                kind: <ChangeKind as WireValue>::decode_atom(&mut fields)?,
                content: <BoundedBytes<LIMIT_BLOB_BYTES> as WireValue>::decode_atom(&mut fields)?,
                content_before: <Option<BoundedBytes<LIMIT_BLOB_BYTES>> as WireValue>::decode_atom(
                    &mut fields,
                )?,
            },
            5 => Self::Unavailable {
                message: <BoundedText<LIMIT_TEXT_BYTES> as WireValue>::decode_atom(&mut fields)?,
            },
            _ => return Err(DecodeError::InvalidValue),
        };
        require_empty(fields)?;
        Ok(value)
    }
}

impl RelationWireValue for FileDiff {
    fn from_relation(value: &RelationValue) -> Result<Self, String> {
        let (case, fields): (&str, &[RelationValue]) = match value {
            RelationValue::Atom(case) => (case, &[]),
            RelationValue::Compound(case, fields) => (case, fields),
            _ => return Err("expected FileDiff relation choice".into()),
        };
        match case {
            "text" => {
                require_relation_arity(fields, 1)?;
                let mut fields = fields.iter();
                Ok(Self::Text {
                    hunks: <BoundedVec<DiffHunk, 0, LIMIT_COLLECTION_ITEMS> as RelationWireValue>::from_relation(fields.next().unwrap())?,
                })
            }
            "deleted" => {
                require_relation_arity(fields, 0)?;
                Ok(Self::Deleted)
            }
            "symlink" => {
                require_relation_arity(fields, 2)?;
                let mut fields = fields.iter();
                Ok(Self::Symlink {
                    kind: <ChangeKind as RelationWireValue>::from_relation(fields.next().unwrap())?,
                    target: <BoundedBytes<LIMIT_PATH_BYTES> as RelationWireValue>::from_relation(
                        fields.next().unwrap(),
                    )?,
                })
            }
            "binary" => {
                require_relation_arity(fields, 3)?;
                let mut fields = fields.iter();
                Ok(Self::Binary {
                    kind: <ChangeKind as RelationWireValue>::from_relation(fields.next().unwrap())?,
                    content: <BoundedBytes<LIMIT_BLOB_BYTES> as RelationWireValue>::from_relation(fields.next().unwrap())?,
                    content_before: <Option<BoundedBytes<LIMIT_BLOB_BYTES>> as RelationWireValue>::from_relation(fields.next().unwrap())?,
                })
            }
            "unavailable" => {
                require_relation_arity(fields, 1)?;
                let mut fields = fields.iter();
                Ok(Self::Unavailable {
                    message: <BoundedText<LIMIT_TEXT_BYTES> as RelationWireValue>::from_relation(
                        fields.next().unwrap(),
                    )?,
                })
            }
            _ => Err(format!("unknown FileDiff relation choice {case}")),
        }
    }
}

